import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/modules/common_params.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:vector_math/vector_math.dart';

/// Declarative config for a standard 2D escape-time fractal.
///
/// Adding a new escape-time fractal = one [EscapeTimeConfig] + one .frag shader.
/// No Dart module file needed.
class EscapeTimeConfig {
  final String id;
  final String name;
  final ModuleNameBuilder? displayName;
  final String shaderAsset;
  final double defaultIterations;
  final double defaultBailout;
  final int defaultColorScheme;
  final double defaultCenterX;
  final double defaultCenterY;
  final double defaultZoom;
  final int maxIterations;
  final String category;
  final List<FractalParameter> extraParams;
  final List<FractalPreset> extraPresets;

  const EscapeTimeConfig({
    required this.id,
    required this.name,
    required this.shaderAsset,
    this.displayName,
    this.defaultIterations = 120,
    this.defaultBailout = 4.0,
    this.defaultColorScheme = 0,
    this.defaultCenterX = 0.0,
    this.defaultCenterY = 0.0,
    this.defaultZoom = 1.0,
    // Most runtime_effect escape-time shaders compile with a static loop cap of 500.
    // Keep the UI/params cap aligned with shader reality to avoid misleading controls.
    this.maxIterations = 500,
    this.category = 'Escape-Time',
    this.extraParams = const [],
    this.extraPresets = const [],
  });
}

/// Builds a [FractalModule] from a declarative [EscapeTimeConfig].
///
/// All standard escape-time fractals share the same uniform layout:
///   float 0: uTime
///   float 1-2: uResolution (vec2)
///   float 3-4: uCenter (vec2)
///   float 5: uZoom
///   float 6: uIterations
///   float 7: uBailout
///   float 8: uColorScheme
///   float 9: uTransparentBg
///   float 10+: extra params (in order)
///
/// This eliminates per-fractal Dart boilerplate.
FractalModule buildEscapeTimeModule(EscapeTimeConfig config) {
  final autoDefaults = _autoDefaultsForModule(config.id);

  var effectiveIterations = config.defaultIterations;
  var effectiveCenterX = config.defaultCenterX;
  var effectiveCenterY = config.defaultCenterY;
  var effectiveZoom = config.defaultZoom;

  if (config.extraPresets.isNotEmpty) {
    // If the module has curated presets, use the first curated preset as
    // default framing/iterations so each fractal starts with a distinctive
    // initial state instead of generic (0,0,1,120).
    final curated = config.extraPresets.first;
    final it = curated.params['iterations'];
    if (it is num) {
      effectiveIterations = it.toDouble();
    }
    // Only use first preset's view if no explicit center/zoom was configured.
    final hasExplicitView = config.defaultCenterX != 0.0 ||
        config.defaultCenterY != 0.0 ||
        config.defaultZoom != 1.0;
    if (!hasExplicitView) {
      effectiveCenterX = curated.view.pan.x;
      effectiveCenterY = curated.view.pan.y;
      effectiveZoom = curated.view.zoom;
    }
  } else {
    // For modules that still use baseline constructor defaults, generate
    // deterministic per-module defaults from the module id.
    final usesBaseIterations = config.defaultIterations == 120;
    final usesBaseCenter =
        config.defaultCenterX == 0.0 && config.defaultCenterY == 0.0;
    final usesBaseZoom = config.defaultZoom == 1.0;

    if (usesBaseIterations) {
      effectiveIterations = autoDefaults.iterations;
    }
    if (usesBaseCenter) {
      effectiveCenterX = autoDefaults.centerX;
      effectiveCenterY = autoDefaults.centerY;
    }
    if (usesBaseZoom) {
      effectiveZoom = autoDefaults.zoom;
    }
  }

  effectiveIterations =
      effectiveIterations.clamp(20.0, config.maxIterations.toDouble());
  effectiveZoom = effectiveZoom.clamp(0.2, 32.0);

  final parameters = [
    CommonFractalParams.iterations(
      defaultValue: effectiveIterations,
      max: config.maxIterations,
    ),
    CommonFractalParams.bailout(defaultValue: config.defaultBailout),
    CommonFractalParams.colorScheme64(defaultValue: config.defaultColorScheme),
    ...config.extraParams,
  ];

  final defaultParams = <String, Object>{
    'iterations': effectiveIterations,
    'bailout': config.defaultBailout,
    'colorScheme': config.defaultColorScheme,
  };
  for (final p in config.extraParams) {
    defaultParams[p.id] = p.defaultValue;
  }

  final defaultPreset = FractalPreset(
    id: '${config.id}-default',
    moduleId: config.id,
    name: 'Default',
    params: defaultParams,
    view: FractalViewState(
      pan: Vector2(effectiveCenterX, effectiveCenterY),
      zoom: effectiveZoom,
      rotation: Vector3.zero(),
    ),
    createdAt: DateTime.now(),
    isBuiltIn: true,
  );

  return FractalModule(
    id: config.id,
    displayName: config.displayName ?? ((_) => config.name),
    dimension: FractalDimension.twoD,
    shaderAsset: config.shaderAsset,
    parameters: parameters,
    defaultPreset: defaultPreset,
    builtInPresets: [
      defaultPreset.copyWith(id: '${config.id}-classic', name: 'Classic'),
      ...config.extraPresets,
    ],
    setUniforms: (shader, state, size, time) {
      shader.setFloat(0, time);
      shader.setFloat(1, size.width);
      shader.setFloat(2, size.height);
      shader.setFloat(3, state.view.pan.x);
      shader.setFloat(4, state.view.pan.y);
      shader.setFloat(5, state.view.zoom);
      shader.setFloat(6, _d(state.params, 'iterations', effectiveIterations));
      shader.setFloat(7, _d(state.params, 'bailout', config.defaultBailout));
      shader.setFloat(
          8,
          _d(state.params, 'colorScheme',
              config.defaultColorScheme.toDouble()));
      shader.setFloat(9, state.transparentBackground ? 1.0 : 0.0);
      // Extra params start at index 10
      for (int i = 0; i < config.extraParams.length; i++) {
        final p = config.extraParams[i];
        shader.setFloat(
            10 + i, _d(state.params, p.id, (p.defaultValue as num).toDouble()));
      }
    },
  );
}

class _AutoModuleDefaults {
  final double centerX;
  final double centerY;
  final double zoom;
  final double iterations;

  const _AutoModuleDefaults({
    required this.centerX,
    required this.centerY,
    required this.zoom,
    required this.iterations,
  });
}

_AutoModuleDefaults _autoDefaultsForModule(String moduleId) {
  final hash = _fnv1a32(moduleId);

  double unit(int shift) => ((hash >> shift) & 0xFF) / 255.0;

  // Keep defaults stable but non-generic per module:
  // - center around the classic Mandelbrot neighborhood
  // - moderate zoom that still shows structure
  // - varied iteration density for immediate detail diversity
  final centerX = -0.55 + (unit(0) - 0.5) * 0.5; // [-0.80, -0.30]
  final centerY = (unit(8) - 0.5) * 0.4; // [-0.20, 0.20]
  final zoom = 0.65 + unit(16) * 0.9; // [0.65, 1.55]
  final iterations = 110.0 + (hash % 131); // [110, 240]

  return _AutoModuleDefaults(
    centerX: centerX,
    centerY: centerY,
    zoom: zoom,
    iterations: iterations,
  );
}

int _fnv1a32(String text) {
  var hash = 0x811C9DC5;
  for (final codeUnit in text.codeUnits) {
    hash ^= codeUnit;
    hash = (hash * 0x01000193) & 0xFFFFFFFF;
  }
  return hash;
}

double _d(Map<String, Object> p, String k, double f) {
  final v = p[k];
  if (v is int) return v.toDouble();
  if (v is double) return v;
  return f;
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/core/models/fractal_preset.dart';
import 'package:flutter_fractals/core/models/fractal_view_state.dart';
import 'package:flutter_fractals/core/modules/common_params.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/param_reader.dart';
import 'package:vector_math/vector_math.dart';

/// Declarative config for a standard 3D ray-marched fractal.
///
/// Adding a new ray-marched 3D fractal = one [Raymarched3DConfig] + one .frag shader.
/// No separate Dart module file needed.
///
/// All 3D ray-marched fractals share this uniform layout (matching mandelbulb.frag):
///   float 0:  uTime
///   float 1-2: uResolution (vec2)
///   float 3-4: uMousePos (vec2, unused placeholder)
///   float 5:  uZoom
///   float 6-8: uRotation (vec3)
///   float 9:  uPower
///   float 10: uIterations
///   float 11: uSteps
///   float 12: uBailout
///   float 13: uColorScheme
///   float 14: uFractalType
///   float 15: uTransparentBg
class Raymarched3DConfig {
  final String id;
  final String name;
  final ModuleNameBuilder? displayName;
  final String shaderAsset;
  final String category;

  // Default parameter values
  final double defaultPower;
  final double minPower;
  final double maxPower;
  final String powerLabel;
  final double defaultIterations;
  final double maxIterations;
  final double defaultSteps;
  final double defaultBailout;
  final int defaultColorScheme;
  final int maxColorScheme;
  final int defaultFractalType;
  final int maxFractalType;
  final List<FractalParamOption> fractalTypeOptions;
  final List<FractalPreset> extraPresets;

  const Raymarched3DConfig({
    required this.id,
    required this.name,
    required this.shaderAsset,
    this.displayName,
    this.category = '3D Fractals',
    this.defaultPower = 8.0,
    this.minPower = 2.0,
    this.maxPower = 12.0,
    this.powerLabel = 'Power',
    this.defaultIterations = 50,
    this.maxIterations = 100,
    this.defaultSteps = 120,
    this.defaultBailout = 2.0,
    this.defaultColorScheme = 0,
    this.maxColorScheme = 3,
    this.defaultFractalType = 0,
    this.maxFractalType = 0,
    this.fractalTypeOptions = const [],
    this.extraPresets = const [],
  });
}

/// Builds a [FractalModule] from a declarative [Raymarched3DConfig].
FractalModule buildRaymarched3DModule(Raymarched3DConfig config) {
  final parameters = [
    FractalParameter(
      id: 'power',
      label: (_) => config.powerLabel,
      type: FractalParamType.float,
      min: config.minPower,
      max: config.maxPower,
      step: 0.1,
      defaultValue: config.defaultPower,
    ),
    CommonFractalParams.iterations(
      defaultValue: config.defaultIterations,
      min: 5,
      max: config.maxIterations,
    ),
    FractalParameter(
      id: 'steps',
      label: (l10n) => l10n.paramSteps,
      type: FractalParamType.integer,
      min: 20,
      max: 200,
      step: 1,
      defaultValue: config.defaultSteps,
    ),
    CommonFractalParams.bailout(
      defaultValue: config.defaultBailout,
      min: 1.0,
      max: 8.0,
    ),
    CommonFractalParams.colorScheme4(
      defaultValue: config.defaultColorScheme.toDouble(),
      max: config.maxColorScheme,
    ),
    if (config.maxFractalType > 0)
      FractalParameter(
        id: 'fractalType',
        label: (_) => 'Variant',
        type: FractalParamType.enumeration,
        min: 0,
        max: config.maxFractalType.toDouble(),
        step: 1,
        defaultValue: config.defaultFractalType.toDouble(),
        options: config.fractalTypeOptions,
      ),
  ];

  final defaultParams = <String, Object>{
    'power': config.defaultPower,
    'iterations': config.defaultIterations,
    'steps': config.defaultSteps,
    'bailout': config.defaultBailout,
    'colorScheme': config.defaultColorScheme,
    if (config.maxFractalType > 0) 'fractalType': config.defaultFractalType,
  };

  final defaultPreset = FractalPreset(
    id: '${config.id}-default',
    moduleId: config.id,
    name: 'Default',
    params: defaultParams,
    view: FractalViewState(
      pan: Vector2.zero(),
      zoom: 1.0,
      rotation: Vector3(0.3, -0.4, 0.0),
    ),
    createdAt: DateTime.utc(2025, 1, 1),
    isBuiltIn: true,
  );

  return FractalModule(
    id: config.id,
    displayName: config.displayName ?? ((_) => config.name),
    dimension: FractalDimension.threeD,
    shaderAsset: config.shaderAsset,
    parameters: parameters,
    defaultPreset: defaultPreset,
    builtInPresets: [
      defaultPreset.copyWith(id: '${config.id}-classic', name: 'Classic'),
      ...config.extraPresets,
    ],
    setUniforms: (shader, state, size, time) {
      shader.setFloat(0, time);
      shader.setFloat(1, size.width);
      shader.setFloat(2, size.height);
      shader.setFloat(3, 0.0); // uMousePos.x (unused)
      shader.setFloat(4, 0.0); // uMousePos.y (unused)
      shader.setFloat(5, state.view.zoom);
      shader.setFloat(6, state.view.rotation.x);
      shader.setFloat(7, state.view.rotation.y);
      shader.setFloat(8, state.view.rotation.z);
      shader.setFloat(
          9, readDouble(state.params, 'power', config.defaultPower));
      shader.setFloat(
          10, readDouble(state.params, 'iterations', config.defaultIterations));
      shader.setFloat(
          11, readDouble(state.params, 'steps', config.defaultSteps));
      shader.setFloat(
          12, readDouble(state.params, 'bailout', config.defaultBailout));
      shader.setFloat(
          13,
          readDouble(state.params, 'colorScheme',
              config.defaultColorScheme.toDouble()));
      shader.setFloat(
          14,
          readDouble(state.params, 'fractalType',
              config.defaultFractalType.toDouble()));
      shader.setFloat(15, state.transparentBackground ? 1.0 : 0.0);
    },
  );
}

import 'package:flutter_test/flutter_test.dart';

import 'package:flutter_fractals/core/modules/builders/escape_time_builder.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time_catalog.dart';

void main() {
  group('Escape-time iteration cap consistency', () {
    test('default EscapeTimeConfig maxIterations matches shader loop cap', () {
      const cfg = EscapeTimeConfig(
        id: 'test',
        name: 'Test',
        shaderAsset: 'shaders/test.frag',
      );
      expect(cfg.maxIterations, 500);
    });

    test('catalog-generated modules keep iterations slider <= 500', () {
      for (final cfg in escapeTimeCatalog) {
        final module = buildEscapeTimeModule(cfg);
        final iterParam =
            module.parameters.firstWhere((p) => p.id == 'iterations');
        expect(
          iterParam.max,
          lessThanOrEqualTo(500.0),
          reason:
              '${cfg.id} exposes iteration max above shader cap: ${iterParam.max}',
        );
      }
    });
  });
}

import 'dart:convert';
import 'package:flutter/foundation.dart';
import 'package:vector_math/vector_math.dart';
import 'fractal_view_state.dart';

/// A saved configuration of fractal parameters and view state.
///
/// Presets allow users to save and restore specific fractal configurations,
/// including both the mathematical parameters (iterations, bailout, etc.)
/// and the view state (pan, zoom, rotation).
///
/// Presets can be:
/// - **Built-in**: Included with the app and read-only
/// - **User-created**: Saved by the user with custom thumbnails
///
/// Presets are serializable to JSON for persistent storage.
///
/// {@category Models}
///
/// Example:
/// ```dart
/// final preset = FractalPreset(
///   id: 'my-preset',
///   moduleId: 'mandelbrot',
///   name: 'Deep Zoom',
///   params: {'iterations': 200, 'colorScheme': 2},
///   view: FractalViewState(
///     pan: Vector2(-0.75, 0.1),
///     zoom: 50.0,
///     rotation: Vector3.zero(),
///   ),
///   createdAt: DateTime.now(),
/// );
/// ```
@immutable
class FractalPreset {
  /// Unique identifier for this preset.
  ///
  /// For built-in presets, use a pattern like 'module-name'.
  /// For user presets, typically a UUID.
  final String id;

  /// The fractal module this preset belongs to.
  ///
  /// Must match a [FractalModule.id] in the registry.
  /// Presets are only applicable to their target module.
  final String moduleId;

  /// User-visible name for this preset.
  ///
  /// Should be descriptive and unique within the module's presets.
  final String name;

  /// The fractal parameter values.
  ///
  /// Keys are parameter IDs (e.g., 'iterations', 'colorScheme').
  /// Values are typed according to [FractalParamType].
  final Map<String, Object> params;

  /// The view state (pan, zoom, rotation) for this preset.
  ///
  /// Defines the camera position and orientation when
  /// the preset is applied.
  final FractalViewState view;

  /// When this preset was created.
  ///
  /// Used for sorting and display purposes.
  final DateTime createdAt;

  /// Whether this is a built-in (read-only) preset.
  ///
  /// Built-in presets cannot be edited or deleted by the user.
  final bool isBuiltIn;

  /// Path to the preset's thumbnail image.
  ///
  /// For user presets, this is typically a file path to a
  /// captured PNG. Built-in presets may use asset paths.
  final String? thumbnailPath;

  /// Creates a new [FractalPreset] with the specified configuration.
  const FractalPreset({
    required this.id,
    required this.moduleId,
    required this.name,
    required this.params,
    required this.view,
    required this.createdAt,
    this.isBuiltIn = false,
    this.thumbnailPath,
  });

  /// Creates a copy of this preset with the given fields replaced.
  ///
  /// Useful for creating variations of existing presets.
  FractalPreset copyWith({
    String? id,
    String? moduleId,
    String? name,
    Map<String, Object>? params,
    FractalViewState? view,
    DateTime? createdAt,
    bool? isBuiltIn,
    String? thumbnailPath,
  }) {
    return FractalPreset(
      id: id ?? this.id,
      moduleId: moduleId ?? this.moduleId,
      name: name ?? this.name,
      params: params ?? this.params,
      view: view ?? this.view,
      createdAt: createdAt ?? this.createdAt,
      isBuiltIn: isBuiltIn ?? this.isBuiltIn,
      thumbnailPath: thumbnailPath ?? this.thumbnailPath,
    );
  }

  /// Serializes this preset to a JSON-compatible map.
  ///
  /// Used for persistent storage in SharedPreferences.
  Map<String, Object?> toJson() {
    return {
      'id': id,
      'moduleId': moduleId,
      'name': name,
      'params': params,
      'view': {
        'panX': view.pan.x,
        'panY': view.pan.y,
        'zoom': view.zoom,
        'rotX': view.rotation.x,
        'rotY': view.rotation.y,
        'rotZ': view.rotation.z,
      },
      'createdAt': createdAt.toIso8601String(),
      'isBuiltIn': isBuiltIn,
      'thumbnailPath': thumbnailPath,
    };
  }

  /// Deserializes a preset from a JSON map.
  ///
  /// Throws if required fields are missing.
  static FractalPreset fromJson(Map<String, Object?> json) {
    final view = json['view'] as Map<String, Object?>? ?? {};
    return FractalPreset(
      id: json['id'] as String,
      moduleId: json['moduleId'] as String,
      name: json['name'] as String,
      params: (json['params'] as Map).map((key, value) => MapEntry(key as String, value as Object)),
      view: FractalViewState(
        pan: Vector2(
          (view['panX'] as num? ?? 0).toDouble(),
          (view['panY'] as num? ?? 0).toDouble(),
        ),
        zoom: (view['zoom'] as num? ?? 1).toDouble(),
        rotation: Vector3(
          (view['rotX'] as num? ?? 0).toDouble(),
          (view['rotY'] as num? ?? 0).toDouble(),
          (view['rotZ'] as num? ?? 0).toDouble(),
        ),
      ),
      createdAt: DateTime.tryParse(json['createdAt'] as String? ?? '') ?? DateTime.now(),
      isBuiltIn: json['isBuiltIn'] as bool? ?? false,
      thumbnailPath: json['thumbnailPath'] as String?,
    );
  }

  /// Parses a list of presets from a JSON string.
  ///
  /// Returns an empty list if [payload] is null or empty.
  /// Skips corrupted entries and continues parsing valid ones.
  /// Used for reading from SharedPreferences.
  static List<FractalPreset> listFromPrefs(String? payload) {
    if (payload == null || payload.isEmpty) {
      return [];
    }
    try {
      final decoded = jsonDecode(payload) as List;
      final presets = <FractalPreset>[];
      for (final item in decoded) {
        try {
          final preset = FractalPreset.fromJson((item as Map).cast<String, Object?>());
          presets.add(preset);
        } catch (e) {
          // Skip corrupted preset, continue with others
          if (kDebugMode) debugPrint('Failed to parse preset: $e');
        }
      }
      return presets;
    } catch (e) {
      // Corrupted JSON, return empty list
      if (kDebugMode) debugPrint('Failed to parse presets JSON: $e');
      return [];
    }
  }

  /// Serializes a list of presets to a JSON string.
  ///
  /// Used for writing to SharedPreferences.
  static String listToPrefs(List<FractalPreset> presets) {
    return jsonEncode(presets.map((preset) => preset.toJson()).toList());
  }
}

/// Safe parameter readers for uniform setters.
double readDouble(Map<String, Object> params, String key, double fallback) {
  final value = params[key];
  if (value is int) return value.toDouble();
  if (value is double) return value;
  return fallback;
}

int readInt(Map<String, Object> params, String key, int fallback) {
  final value = params[key];
  if (value is int) return value;
  if (value is double) return value.round();
  return fallback;
}

